import{c as e,Q as n,j as a,m as o}from"./chunks/framework.BXc4yaFE.js";const p=JSON.parse('{"title":"δ-mem: Efficient Online Memory for Large Language Models","description":"","frontmatter":{"title":"δ-mem: Efficient Online Memory for Large Language Models","authors":"Jingdi Lei, Di Zhang, Junxian Li, Weida Wang, Kaixuan Fan, Xiang Liu, Qihan Liu, Xiaoteng Ma, Baian Chen, Soujanya Poria","published":"2026-05-12T00:00:00.000Z","source":"https://arxiv.org/abs/2605.12357"},"headers":[],"relativePath":"research/papers/2026-05-12-delta-mem-efficient-online-memory-llm-2605-12357.md","filePath":"research/papers/2026-05-12-delta-mem-efficient-online-memory-llm-2605-12357.md","lastUpdated":1779901665000}'),r={name:"research/papers/2026-05-12-delta-mem-efficient-online-memory-llm-2605-12357.md"};function i(s,t,d,l,c,m){return n(),a("div",null,[...t[0]||(t[0]=[o(`<h1 id="δ-mem-efficient-online-memory-for-large-language-models" tabindex="-1">δ-mem: Efficient Online Memory for Large Language Models <a class="header-anchor" href="#δ-mem-efficient-online-memory-for-large-language-models" aria-label="Permalink to &quot;δ-mem: Efficient Online Memory for Large Language Models&quot;">​</a></h1><p><strong>Authors</strong>: Jingdi Lei†, Di Zhang†, Junxian Li, Weida Wang, Kaixuan Fan†, Xiang Liu†, Qihan Liu, Xiaoteng Ma, Baian Chen, Soujanya Poria (†equal contribution) <strong>Affiliations</strong>: Nanyang Technological University, Fudan University, MindLab, Shanghai Jiao Tong University, The Chinese University of Hong Kong, HKUST (Guangzhou) <strong>Published</strong>: May 12, 2026 <strong>Source</strong>: <a href="https://arxiv.org/abs/2605.12357" target="_blank" rel="noreferrer">https://arxiv.org/abs/2605.12357</a><strong>arXiv ID</strong>: 2605.12357 <strong>Categories</strong>: cs.AI <strong>GitHub</strong>: Declare-lab &amp; MindLab-Research</p><hr><h2 id="abstract" tabindex="-1">Abstract <a class="header-anchor" href="#abstract" aria-label="Permalink to &quot;Abstract&quot;">​</a></h2><p>Large language models increasingly need to accumulate and reuse historical information in long-term assistants and agent systems. Simply expanding the context window is costly and often fails to ensure effective context utilization. We propose δ-mem, a lightweight memory mechanism that augments a frozen full-attention backbone with a compact online state of associative memory. δ-mem compresses past information into a fixed-size state matrix updated by delta-rule learning, and uses its readout to generate low-rank corrections to the backbone&#39;s attention computation during generation. With only an 8×8 online memory state, δ-mem improves the average score to 1.10× that of the frozen backbone and 1.15× that of the strongest non-δ-mem memory baseline. It achieves larger gains on memory-heavy benchmarks, reaching 1.31× on MemoryAgentBench and 1.20× on LoCoMo, while largely preserving general capabilities. These results show that effective memory can be realized through a compact online state directly coupled with attention computation, without full fine-tuning, backbone replacement, or explicit context extension.</p><hr><h2 id="_1-introduction" tabindex="-1">1. Introduction <a class="header-anchor" href="#_1-introduction" aria-label="Permalink to &quot;1. Introduction&quot;">​</a></h2><h3 id="problem" tabindex="-1">Problem <a class="header-anchor" href="#problem" aria-label="Permalink to &quot;Problem&quot;">​</a></h3><p>LLMs deployed in long-term personalized assistants and long-horizon agent systems must accumulate, update, and reuse historical information over extended memory-heavy tasks. Model performance depends not only on understanding the current input, but also on effectively leveraging relevant past context during test-time.</p><p><strong>Context window expansion alone is insufficient</strong>:</p><ul><li>Standard attention incurs quadratic cost with respect to context length</li><li>Models suffer from context degradation or &quot;context rot&quot; when context becomes very long</li><li>Even million-token context windows do not fundamentally solve the memory problem</li></ul><h3 id="taxonomy-of-existing-memory-mechanisms-mms" tabindex="-1">Taxonomy of Existing Memory Mechanisms (MMs) <a class="header-anchor" href="#taxonomy-of-existing-memory-mechanisms-mms" aria-label="Permalink to &quot;Taxonomy of Existing Memory Mechanisms (MMs)&quot;">​</a></h3><p>Characterized along two dimensions:</p><ol><li><strong>Memory state</strong> — how historical information is stored</li><li><strong>Memory steering</strong> — how stored information influences backbone reasoning</li></ol><p>Three paradigms:</p><table tabindex="0"><thead><tr><th>Paradigm</th><th>How it stores</th><th>How it steers</th><th>Limitation</th></tr></thead><tbody><tr><td>Textual Memory Mechanisms (TMMs)</td><td>Text entries / summaries</td><td>Re-inject into input context</td><td>Context-window limits, retrieval noise, compaction loss</td></tr><tr><td>Outside-Channel Memory Mechanisms (OMMs)</td><td>External latent modules</td><td>Retrieval / encoding on outside pathways</td><td>Overhead, integration complexity, misalignment</td></tr><tr><td>Parametric Memory Mechanisms (PMMs)</td><td>Prefixes or adapter parameters</td><td>Static parameter modification</td><td>Static nature limits adaptation to dynamically evolving information</td></tr></tbody></table><h3 id="proposal-δ-mem" tabindex="-1">Proposal: δ-mem <a class="header-anchor" href="#proposal-δ-mem" aria-label="Permalink to &quot;Proposal: δ-mem&quot;">​</a></h3><p>A memory mechanism that keeps a <strong>compact, dynamically updated</strong> online state alongside a <strong>frozen full-attention backbone</strong>:</p><ul><li>Compresses past info into an <strong>Online State of Associative Memory (OSAM)</strong> — a fixed-size matrix</li><li>State continuously updated via <strong>delta-rule learning</strong> as new tokens arrive</li><li>During generation: current input queries state → extracts associative signals → transformed into <strong>low-rank corrections</strong> to backbone attention</li><li>State further updated after each interaction, enabling δ-mem to evolve over time</li></ul><hr><h2 id="_2-preliminaries-notation" tabindex="-1">2. Preliminaries &amp; Notation <a class="header-anchor" href="#_2-preliminaries-notation" aria-label="Permalink to &quot;2. Preliminaries &amp; Notation&quot;">​</a></h2><ul><li>Input hidden sequence: <strong>x ∈ ℝ^(N×d)</strong>, N = sequence length, d = hidden dimension</li><li>Single-position hidden state: x_t ∈ ℝ^d (column vector)</li><li>Q, K, V: standard attention query/key/value</li><li>S_t: online state after processing position t</li><li>δ-mem maintains matrix <strong>S</strong> as the online state of associative memory</li></ul><p><strong>Delta-rule update</strong> (base form):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Given memory key k_t ∈ ℝ^r, value v_t ∈ ℝ^r:</span></span>
<span class="line"><span>  Prediction: v̂_t = S_{t-1} k_t</span></span>
<span class="line"><span>  Residual loss: L_t(S) = ‖Sk_t - v_t‖²</span></span>
<span class="line"><span>  Update: S_t = S_{t-1} + η_t(v_t - S_{t-1}k_t)k_t^T</span></span></code></pre></div><p>This writes only the <strong>residual information</strong> along the key direction — well-learned associations induce negligible updates; predictive discrepancies dynamically correct the state.</p><p><strong>Gated delta update</strong> (with forget gate, inspired by Qwen-Next):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>S_t = Γ_t ⊙ S_{t-1} + Δ_t ⊙ (v_t - S_{t-1}k_t)k_t^T</span></span></code></pre></div><ul><li>Γ_t controls how much previous memory is retained</li><li>Δ_t controls the strength of the residual write</li></ul><hr><h2 id="_3-δ-mem-architecture" tabindex="-1">3. δ-mem Architecture <a class="header-anchor" href="#_3-δ-mem-architecture" aria-label="Permalink to &quot;3. δ-mem Architecture&quot;">​</a></h2><h3 id="computation-order-per-position" tabindex="-1">Computation Order (per position) <a class="header-anchor" href="#computation-order-per-position" aria-label="Permalink to &quot;Computation Order (per position)&quot;">​</a></h3><ol><li><strong>Read</strong> associative memory signals from old state</li><li><strong>Steer</strong> attention using those signals (low-rank corrections)</li><li><strong>Write</strong> current information into the state</li></ol><h3 id="_3-1-memory-projections" tabindex="-1">3.1 Memory Projections <a class="header-anchor" href="#_3-1-memory-projections" aria-label="Permalink to &quot;3.1 Memory Projections&quot;">​</a></h3><p>Projects hidden state x_t into low-dimensional associative memory space (dimension r):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>q^m_t = L-norm(tanh(W^m_q x_t))   # query: reads from old state</span></span>
<span class="line"><span>k^m_t = L-norm(tanh(W^m_k x_t))   # key: how to write</span></span>
<span class="line"><span>v^m_t = W^m_v x_t                  # value: what to write</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Γ_t = σ(W_Γ x_t + b)              # retention gate ∈ ℝ^r</span></span>
<span class="line"><span>Δ_t = 1 - Γ_t                      # write gate</span></span></code></pre></div><p>Normalizing query and key reduces state instability from scale drift during long-sequence recurrence. Dimension-wise gating allows some dimensions to retain old memory while others write current information more actively.</p><h3 id="_3-2-reading-from-online-state-of-associative-memory-osam" tabindex="-1">3.2 Reading from Online State of Associative Memory (OSAM) <a class="header-anchor" href="#_3-2-reading-from-online-state-of-associative-memory-osam" aria-label="Permalink to &quot;3.2 Reading from Online State of Associative Memory (OSAM)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>r_t = S_{t-1} q^m_t</span></span></code></pre></div><ul><li>Read vector r_t ∈ ℝ^r from old state with current input as query</li><li>Cost is <strong>independent of history length</strong> (fixed-size state)</li><li>Complementary to standard attention: attention compares query with all keys in explicit context; δ-mem provides <strong>history-dependent steering signals</strong> from the compressed state</li></ul><h3 id="_3-3-steering-attention-via-low-rank-corrections" tabindex="-1">3.3 Steering Attention via Low-Rank Corrections <a class="header-anchor" href="#_3-3-steering-attention-via-low-rank-corrections" aria-label="Permalink to &quot;3.3 Steering Attention via Low-Rank Corrections&quot;">​</a></h3><p>Read signal projected into query-side and output-side corrections:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>δq_t = W_δq r_t      # query-side correction</span></span>
<span class="line"><span>δo_t = W_δo r_t      # output-side correction</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Corrected query:</span></span>
<span class="line"><span>q̃_t = q_t + √r · δq_t    where q_t = W_Q x_t</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Attention with corrected query:</span></span>
<span class="line"><span>a_t = Attn(q̃_t, K_t, V_t)</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Final output with output-side correction:</span></span>
<span class="line"><span>ỹ_t = a_t + √r · δo_t</span></span></code></pre></div><p><strong>Key distinction from static adapters</strong>: Although W_δq and W_δo are fixed after training, their input r_t comes from the dynamic state S_{t-1}. Therefore, the same set of parameters produces <strong>different steering effects</strong> under different histories.</p><h3 id="_3-4-writing-into-online-state" tabindex="-1">3.4 Writing into Online State <a class="header-anchor" href="#_3-4-writing-into-online-state" aria-label="Permalink to &quot;3.4 Writing into Online State&quot;">​</a></h3><p>After attention, writes current position&#39;s information into online state:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>S_t = Diag(Γ_t) S_{t-1} + Diag(Δ_t)(v^m_t - S_{t-1}k^m_t)k^m_t^T</span></span></code></pre></div><p>Three terms:</p><ol><li><strong>Retain</strong>: Diag(Γ_t) S_{t-1} — retains previous state</li><li><strong>Erase</strong>: -Diag(Δ_t) S_{t-1}k^m_t k^m_t^T — removes old prediction along current key direction</li><li><strong>Write</strong>: +Diag(Δ_t) v^m_t k^m_t^T — writes new value into same direction</li></ol><p>Memory state updated by <strong>error correction with controlled forgetting</strong>, not by unselectly accumulating new outer products.</p><h3 id="_3-5-writing-granularity-strategies" tabindex="-1">3.5 Writing Granularity Strategies <a class="header-anchor" href="#_3-5-writing-granularity-strategies" aria-label="Permalink to &quot;3.5 Writing Granularity Strategies&quot;">​</a></h3><p>Three strategies for when to write into the state:</p><table tabindex="0"><thead><tr><th>Strategy</th><th>Abbreviation</th><th>Write trigger</th><th>Pros</th><th>Cons</th></tr></thead><tbody><tr><td>Token-State Write</td><td>TSW</td><td>Every token</td><td>Finest granularity, captures local changes</td><td>Affected by format symbols, repeated expressions, short-term noise</td></tr><tr><td>Sequence-State Write</td><td>SSW</td><td>Per message segment (averaged hidden states)</td><td>Reduces redundant writes, smoothed evolution</td><td>Fine-grained token details absorbed by average</td></tr><tr><td>Multi-State Write</td><td>MSW</td><td>Per token, across N parallel sub-states</td><td>Reduces mutual interference between memory types</td><td>More parameters</td></tr></tbody></table><p><strong>MSW formulation</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>S_t = {S^(1)_t, ..., S^(N)_t}</span></span>
<span class="line"><span>S^(i)_t = Update^(i)(S^(i)_{t-1}, x_t)</span></span>
<span class="line"><span>r_t = Concat(r^(1)_t, ..., r^(N)_t)</span></span></code></pre></div><h3 id="_3-6-training-objective" tabindex="-1">3.6 Training Objective <a class="header-anchor" href="#_3-6-training-objective" aria-label="Permalink to &quot;3.6 Training Objective&quot;">​</a></h3><p>Standard SFT loss. Context tokens written into online state first (producing S_C), <strong>not replayed as explicit backbone inputs</strong> during prediction. Frozen backbone only receives query Q and response Y, state steers attention through δ-mem:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>L_SFT = -Σ_j log p_{φ,θ}(y_j | Q, y_{&lt;j}, S_C)</span></span></code></pre></div><ul><li>θ = trainable δ-mem parameters</li><li>φ = frozen backbone parameters</li></ul><hr><h2 id="_4-experiments" tabindex="-1">4. Experiments <a class="header-anchor" href="#_4-experiments" aria-label="Permalink to &quot;4. Experiments&quot;">​</a></h2><h3 id="_4-1-setup" tabindex="-1">4.1 Setup <a class="header-anchor" href="#_4-1-setup" aria-label="Permalink to &quot;4.1 Setup&quot;">​</a></h3><p><strong>Backbone models</strong>:</p><ul><li>Qwen3-4B-Instruct</li><li>Qwen3-8B</li><li>SmolLM3-3B</li></ul><p><strong>Benchmarks</strong>:</p><table tabindex="0"><thead><tr><th>Type</th><th>Benchmark</th><th>What it measures</th></tr></thead><tbody><tr><td>General</td><td>HotpotQA</td><td>Multi-hop reasoning, knowledge-intensive QA</td></tr><tr><td>General</td><td>GPQA-Diamond</td><td>Knowledge-intensive QA</td></tr><tr><td>General</td><td>IFEval</td><td>Instruction following</td></tr><tr><td>Memory-heavy</td><td>LoCoMo</td><td>Long-context conversational memory</td></tr><tr><td>Memory-heavy</td><td>MemoryAgentBench</td><td>Retention, retrieval, and utilization across extended interactions</td></tr></tbody></table><p><strong>Baselines</strong>:</p><ul><li>Textual: BM25RAG, LLMLingua-2, MemoryBank</li><li>Parametric: Context2LoRA, MemGen</li><li>Outside-channel: MLP Memory</li></ul><h3 id="_4-2-main-results-qwen3-4b-instruct-backbone" tabindex="-1">4.2 Main Results (Qwen3-4B-Instruct backbone) <a class="header-anchor" href="#_4-2-main-results-qwen3-4b-instruct-backbone" aria-label="Permalink to &quot;4.2 Main Results (Qwen3-4B-Instruct backbone)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Model</th><th>IFEval</th><th>HotpotQA EM</th><th>HotpotQA F1</th><th>GPQA-D</th><th>MemAgentBench Avg</th><th>LoCoMo Avg</th><th><strong>Final Avg</strong></th></tr></thead><tbody><tr><td>Qwen3-4B-Instruct (baseline)</td><td>81.89</td><td>42.35</td><td>56.00</td><td>39.39</td><td>29.54</td><td>40.79</td><td>46.79</td></tr><tr><td>+BM25RAG</td><td>—</td><td>40.35</td><td>52.83</td><td>—</td><td>24.49</td><td>36.68</td><td>—</td></tr><tr><td>+LLMLingua-2</td><td>—</td><td>36.93</td><td>50.03</td><td>—</td><td>15.63</td><td>40.98</td><td>—</td></tr><tr><td>+MemoryBank</td><td>—</td><td>—</td><td>—</td><td>—</td><td>17.65</td><td>38.14</td><td>—</td></tr><tr><td>+Context2LoRA</td><td>76.71</td><td>37.85</td><td>50.88</td><td>29.29</td><td>32.53</td><td>48.11</td><td>44.90</td></tr><tr><td>+MemGen</td><td>39.37</td><td>5.36</td><td>16.27</td><td>38.89</td><td>29.61</td><td>40.05</td><td>30.66</td></tr><tr><td>+MLP Memory</td><td>24.95</td><td>10.94</td><td>25.83</td><td>22.73</td><td>28.80</td><td>26.85</td><td>22.85</td></tr><tr><td><strong>+δ-Mem (SSW)</strong></td><td>81.70</td><td>49.22</td><td>63.43</td><td><strong>41.41</strong></td><td>37.84</td><td>47.05</td><td><strong>51.44</strong></td></tr><tr><td><strong>+δ-Mem (TSW)</strong></td><td><strong>82.99</strong></td><td><strong>49.41</strong></td><td><strong>63.66</strong></td><td>40.40</td><td>36.48</td><td>46.53</td><td><strong>51.66</strong></td></tr><tr><td><strong>+δ-Mem (MSW)</strong></td><td>81.52</td><td>46.86</td><td>60.47</td><td>37.37</td><td><strong>38.85</strong></td><td><strong>49.12</strong></td><td><strong>50.74</strong></td></tr></tbody></table><p><strong>Key findings</strong>:</p><ul><li>TSW achieves best average (51.66%), +4.87 over backbone, +6.76 over Context2LoRA</li><li>MSW best on MemoryAgentBench (38.85%) and LoCoMo (49.12%)</li><li>SSW best at GPQA-Diamond (41.41%)</li><li>Textual memory methods show inconsistent gains due to retrieval noise and compaction loss</li><li>Context2LoRA over-fits training distribution</li><li>MLP Memory lacks sequential state accumulation</li></ul><h3 id="_4-3-cross-backbone-results" tabindex="-1">4.3 Cross-Backbone Results <a class="header-anchor" href="#_4-3-cross-backbone-results" aria-label="Permalink to &quot;4.3 Cross-Backbone Results&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Model</th><th>Baseline Avg</th><th>Best δ-Mem Avg</th><th>Strategy</th><th>Gain</th></tr></thead><tbody><tr><td>Qwen3-4B-Instruct</td><td>46.79%</td><td>51.66%</td><td>TSW</td><td>+4.87</td></tr><tr><td>Qwen3-8B</td><td>47.20%</td><td>50.86%</td><td>SSW</td><td>+3.66</td></tr><tr><td>SmolLM3-3B</td><td>26.08%</td><td>36.96%</td><td>MSW</td><td>+10.88</td></tr></tbody></table><p><strong>Pattern</strong>: More capable models benefit more from SSW (smoother state updates); smaller models benefit more from MSW (separating memory reduces interference).</p><hr><h2 id="_5-ablative-studies" tabindex="-1">5. Ablative Studies <a class="header-anchor" href="#_5-ablative-studies" aria-label="Permalink to &quot;5. Ablative Studies&quot;">​</a></h2><h3 id="_5-1-context-recovery-no-context-setting" tabindex="-1">5.1 Context Recovery (No-Context Setting) <a class="header-anchor" href="#_5-1-context-recovery-no-context-setting" aria-label="Permalink to &quot;5.1 Context Recovery (No-Context Setting)&quot;">​</a></h3><p>Tests whether OSAM can preserve useful historical information <strong>without explicit context replay</strong> — history removed, only compressed memory state injected:</p><table tabindex="0"><thead><tr><th>Benchmark</th><th>Metric</th><th>No-context baseline</th><th>δ-Mem (no context)</th></tr></thead><tbody><tr><td>HotpotQA (Bridge)</td><td>EM</td><td>0.08%</td><td>3.97%</td></tr><tr><td>HotpotQA (Bridge)</td><td>F1</td><td>6.25%</td><td>11.05%</td></tr><tr><td>HotpotQA (Overall)</td><td>EM</td><td>0.08%</td><td>6.48%</td></tr><tr><td>HotpotQA (Overall)</td><td>F1</td><td>8.27%</td><td>15.20%</td></tr><tr><td>LoCoMo (Overall)</td><td>Avg</td><td>3.49%</td><td>8.05%</td></tr></tbody></table><p><strong>Conclusion</strong>: Online state stores context-relevant historical signals that can be reused when explicit context is unavailable.</p><h3 id="_5-2-attention-head-ablation" tabindex="-1">5.2 Attention Head Ablation <a class="header-anchor" href="#_5-2-attention-head-ablation" aria-label="Permalink to &quot;5.2 Attention Head Ablation&quot;">​</a></h3><p>Where should memory-induced correction be injected within the attention block?</p><table tabindex="0"><thead><tr><th>Configuration</th><th>HotpotQA EM</th><th>LoCoMo Avg</th><th>Final Avg</th></tr></thead><tbody><tr><td>q only</td><td>45.87</td><td>42.43</td><td>43.15</td></tr><tr><td>k only</td><td>43.39</td><td>38.44</td><td>42.19</td></tr><tr><td>v only</td><td>46.12</td><td>39.54</td><td>44.24</td></tr><tr><td><strong>o only</strong></td><td><strong>48.94</strong></td><td><strong>39.68</strong></td><td><strong>47.05</strong></td></tr><tr><td><strong>q+o (default)</strong></td><td><strong>49.41</strong></td><td><strong>42.14</strong></td><td><strong>47.97</strong></td></tr><tr><td>q+k+v+o (full)</td><td>49.94</td><td>41.08</td><td><strong>48.05</strong></td></tr></tbody></table><p><strong>Default choice</strong>: q+o offers the best performance-efficiency trade-off; qkvo gives marginal gain at extra parameter overhead.</p><h3 id="_5-3-insertion-depth-ablation" tabindex="-1">5.3 Insertion Depth Ablation <a class="header-anchor" href="#_5-3-insertion-depth-ablation" aria-label="Permalink to &quot;5.3 Insertion Depth Ablation&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Layer configuration</th><th>HotpotQA EM</th><th>LoCoMo Avg</th><th>Final Avg</th></tr></thead><tbody><tr><td>Front 12 layers</td><td>45.52</td><td>39.06</td><td>44.39</td></tr><tr><td>Middle 12 layers</td><td>47.44</td><td>44.00</td><td>46.66</td></tr><tr><td>Back 12 layers</td><td>44.58</td><td>40.60</td><td>44.06</td></tr><tr><td><strong>All layers</strong></td><td><strong>49.41</strong></td><td><strong>42.14</strong></td><td><strong>47.97</strong></td></tr></tbody></table><p><strong>Best</strong>: All layers. Middle layers outperform front/back among partial configurations — intermediate layers provide effective memory injection interface, balancing semantic abstraction and task-specific computation.</p><hr><h2 id="_6-related-work" tabindex="-1">6. Related Work <a class="header-anchor" href="#_6-related-work" aria-label="Permalink to &quot;6. Related Work&quot;">​</a></h2><h3 id="textual-memory-mechanisms-tmms" tabindex="-1">Textual Memory Mechanisms (TMMs) <a class="header-anchor" href="#textual-memory-mechanisms-tmms" aria-label="Permalink to &quot;Textual Memory Mechanisms (TMMs)&quot;">​</a></h3><p>Early RAG systems (Lewis et al. 2020; Borgeaud et al. 2022); agent-oriented methods (MemGPT, MemoryBank, Mem0) extend to continuous interaction via logging, summarization, reflection. Constrained by tokenized form: sensitive to compression fidelity, retrieval noise, context budget.</p><p><strong>δ-mem difference</strong>: Does not route compressed history back through token space; maintains compact online state and steers Transformer through low-rank attention corrections.</p><h3 id="outside-channel-memory-mechanisms-omms" tabindex="-1">Outside-Channel Memory Mechanisms (OMMs) <a class="header-anchor" href="#outside-channel-memory-mechanisms-omms" aria-label="Permalink to &quot;Outside-Channel Memory Mechanisms (OMMs)&quot;">​</a></h3><p>Memorizing Transformers (Wu et al. 2022): stores past internal representations as non-differentiable key-value memories, retrieves via approximate kNN. LongMem (Wang et al. 2023): frozen backbone as memory encoder + adaptive residual side network.</p><p><strong>δ-mem difference</strong>: Memory not retrieved as auxiliary external source; compact online state directly produces low-rank corrections to attention computation — memory participates in the current forward pass.</p><h3 id="parametric-memory-mechanisms-pmms" tabindex="-1">Parametric Memory Mechanisms (PMMs) <a class="header-anchor" href="#parametric-memory-mechanisms-pmms" aria-label="Permalink to &quot;Parametric Memory Mechanisms (PMMs)&quot;">​</a></h3><p>Prefix-Tuning, LoRA, ROME, MEMIT. Generally fixed after training or updated through discrete editing steps, not continuously evolving with the sequence.</p><p><strong>δ-mem difference</strong>: LoRA&#39;s low-rank update is static; δ-mem generates low-rank attention corrections from a compact online state at runtime — same parameters, different steering effects per history.</p><hr><h2 id="_7-conclusion" tabindex="-1">7. Conclusion <a class="header-anchor" href="#_7-conclusion" aria-label="Permalink to &quot;7. Conclusion&quot;">​</a></h2><p>δ-mem equips a frozen full-attention backbone with a compact, dynamically updated online state of associative memory. Key properties:</p><ol><li><strong>No backbone modification</strong>: frozen throughout training and inference</li><li><strong>Fixed-size state</strong>: even 8×8 (64 entries) suffices for measurable gains</li><li><strong>Directly coupled with attention</strong>: not a separate retrieval system</li><li><strong>Online / streaming</strong>: evolves with the sequence during generation</li><li><strong>Context recovery</strong>: stores signals reusable even when explicit context is removed</li></ol><p>Results suggest compact online states can serve as a scalable and efficient interface for test-time memory in frozen Transformer backbones.</p><hr><h2 id="key-numbers-summary" tabindex="-1">Key Numbers Summary <a class="header-anchor" href="#key-numbers-summary" aria-label="Permalink to &quot;Key Numbers Summary&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Metric</th><th>Value</th></tr></thead><tbody><tr><td>Memory state size</td><td>8×8 = 64 entries</td></tr><tr><td>Average score vs frozen backbone</td><td>1.10×</td></tr><tr><td>Average score vs strongest non-δ-mem baseline</td><td>1.15×</td></tr><tr><td>MemoryAgentBench improvement</td><td>1.31×</td></tr><tr><td>LoCoMo improvement</td><td>1.20×</td></tr><tr><td>TTL subtask (MemoryAgentBench)</td><td>nearly 2× (35.30% → 50.50%)</td></tr><tr><td>Best backbone (SmolLM3-3B) gain</td><td>26.08% → 36.96% (+10.88pp)</td></tr><tr><td>Context recovery HotpotQA EM</td><td>0.08% → 6.48% (no explicit context)</td></tr></tbody></table>`,106)])])}const g=e(r,[["render",i]]);export{p as __pageData,g as default};
